{
    static void Main()
    {
        var seen = new HashSet<int>();
        Console.WriteLine(seen.Add(1));    // True
        Console.WriteLine(seen.Add(2));    // True
        Console.WriteLine(seen.Add(1));    // False (duplicate)
        Console.WriteLine(seen.Count);     // 2
        Console.WriteLine(seen.Contains(2)); // True
        seen.Remove(2);
        Console.WriteLine(seen.Contains(2)); // False
    }
}

