class Program
{
    static void Main()
    {
        int[] nums = { 4, 2, 7, 2, 4, 1, 7, 3 };

        var unique = new HashSet<int>(nums);
        Console.WriteLine(String.Join(", ", unique));

        var orderedUnique = new List<int>();
        var seen = new HashSet<int>();
        foreach (int n in nums)
        {
            if (seen.Add(n))
                orderedUnique.Add(n);
        }
        Console.WriteLine(String.Join(", ", orderedUnique));  // 4, 2, 7, 1, 3
    }
}

